// Get input data from previous node
const items = $input.all();

// Process each row and merge everything into a single content string
const formattedData = items.map(item => {
    const row = item.json; // Extract row data

    // Merge all fields (column names and values) into a single content field
    const content = Object.entries(row)
        .map(([key, value]) => `${key}: ${value !== null ? value : 'N/A'}`) // Handle null values
        .join(" | "); // Use separator for clarity

    return {
        json: {

            content: content,  // Single merged content string

        }
    };
});

// Return formatted data
return formattedData;

// This function extracts text from HTML while preserving basic structure
function extractTextFromHtml(html) {
  if (!html) return '';

  // Replace paragraphs with newlines
  let text = html.replace(/<p[^>]*>(.*?)<\/p>/g, '$1\n');

  // Replace headers with their content
  text = text.replace(/<h[1-6][^>]*>(.*?)<\/h[1-6]>/g, '$1\n');

  // Replace list items with bullet points
  text = text.replace(/<li[^>]*>(.*?)<\/li>/g, '• $1\n');

  // Replace strong tags
  text = text.replace(/<strong>(.*?)<\/strong>/g, '$1');

  // Replace emphasis/italic tags
  text = text.replace(/<i>(.*?)<\/i>/g, '$1');
  text = text.replace(/<em>(.*?)<\/em>/g, '$1');

  // Replace links with just their text
  text = text.replace(/<a[^>]*>(.*?)<\/a>/g, '$1');

  // Replace special characters
  text = text.replace(/&nbsp;/g, ' ');
  text = text.replace(/&amp;/g, '&');
  text = text.replace(/&lt;/g, '<');
  text = text.replace(/&gt;/g, '>');

  // Remove remaining HTML tags
  text = text.replace(/<[^>]*>/g, '');

  // Clean up whitespace
  text = text.replace(/\s+/g, ' ');
  text = text.replace(/\n\s*\n/g, '\n');

  return text.trim();
}

// Process a single SharePoint JSON object
function processSharePointData(jsonData) {
  try {
    // Extract page ID from @odata.context
    const context = jsonData['@odata.context'] || '';
    const pageIdMatch = context.match(/pages\('([^']+)'\)/);
    const pageId = pageIdMatch ? pageIdMatch[1] : "unknown";

    // Extract content from web parts
    const contentParts = [];

    if (Array.isArray(jsonData.value)) {
      jsonData.value.forEach(webPart => {
        // Handle text web parts
        if (webPart['@odata.type'] === '#microsoft.graph.textWebPart') {
          const innerHtml = webPart.innerHtml || '';
          contentParts.push(extractTextFromHtml(innerHtml));
        }

        // Handle standard web parts
        else if (webPart['@odata.type'] === '#microsoft.graph.standardWebPart') {
          const webPartData = webPart.data || {};
          const description = webPartData.description || '';
          const title = webPartData.title || '';

          if (description || title) {
            contentParts.push(`${description} ${title}`);
          }

          // Extract properties
          const properties = webPartData.properties || {};
          if (properties && properties.title) {
            contentParts.push(properties.title);
          }
        }
      });
    }

    const content = contentParts.join(' ');

    return {
      id: pageId,
      content: content,
      formattedOutput: `id:${pageId}\ncontent:${content}`
    };
  } catch (error) {
    return {
      id: "error",
      content: `Error processing data: ${error.message}`,
      formattedOutput: `id:error\ncontent:Error processing data: ${error.message}`
    };
  }
}

// Main function to process all input items
function processItems(items) {
  const results = [];

  for (const item of items) {
    try {
      // Access the data field which contains the JSON string
      const jsonString = item.json.data;

      // Parse the JSON string
      const jsonData = JSON.parse(jsonString);

      // Process the SharePoint data
      const result = processSharePointData(jsonData);

      // Add the result to the output
      results.push({
        json: result
      });
    } catch (error) {
      results.push({
        json: {
          id: "parsing_error",
          content: `Error parsing JSON: ${error.message}`,
          formattedOutput: `id:parsing_error\ncontent:Error parsing JSON: ${error.message}`,
          error: error.message
        }
      });
    }
  }

  return results;
}

// Execute the function with the items from n8n
return processItems($input.all());

// Process a single SharePoint page entity
function processSharePointPageEntity(jsonData) {
  try {
    // Extract page ID directly from the id field
    const pageId = jsonData.id || "unknown";

    // Extract content from various fields
    const contentParts = [];

    // Add title from name field (removing file extension and converting dashes to spaces)
    if (jsonData.name) {
      const title = jsonData.name
        .replace(/\.aspx$/, '')
        .replace(/-/g, ' ');
      contentParts.push(title);
    }

    // Add description if available
    if (jsonData.description) {
      contentParts.push(jsonData.description);
    }

    const content = contentParts.join(' ');

    // Extract additional information
    const webUrl = jsonData.webUrl || "unknown";
    const createdDateTime = jsonData.createdDateTime || "unknown";
    const lastModifiedDateTime = jsonData.lastModifiedDateTime || "unknown";

    // Extract creator information
    let creatorName = "unknown";
    let creatorEmail = "unknown";

    // Check different possible locations for creator info
    if (jsonData.createdBy && jsonData.createdBy.user) {
      creatorName = jsonData.createdBy.user.displayName || "unknown";
      creatorEmail = jsonData.createdBy.user.email || "unknown";
    } else if (jsonData.lastModifiedBy && jsonData.lastModifiedBy.user) {
      // Fallback to modifier if creator is not available
      creatorName = jsonData.lastModifiedBy.user.displayName || "unknown";
      creatorEmail = jsonData.lastModifiedBy.user.email || "unknown";
    }

    return {
      id: pageId,
      content: content,
      webUrl: webUrl,
      creatorName: creatorName,
      creatorEmail: creatorEmail,
      createdDateTime: createdDateTime,
      lastModifiedDateTime: lastModifiedDateTime,
      formattedOutput: `id:${pageId}\ncontent:${content}\nwebUrl:${webUrl}\ncreator:${creatorName} (${creatorEmail})\ncreated:${createdDateTime}\nlastModified:${lastModifiedDateTime}`
    };
  } catch (error) {
    return {
      id: "error",
      content: `Error processing data: ${error.message}`,
      webUrl: "unknown",
      creatorName: "unknown",
      creatorEmail: "unknown",
      createdDateTime: "unknown",
      lastModifiedDateTime: "unknown",
      formattedOutput: `id:error\ncontent:Error processing data: ${error.message}`
    };
  }
}

// Main function to process all input items
function processItems(items) {
  const results = [];

  for (const item of items) {
    try {
      // Access the data field which contains the JSON string
      const jsonString = item.json.data;

      // Handle potentially truncated JSON by removing trailing comma or incomplete property
      const cleanedJsonString = jsonString.replace(/,\s*"[^"]*$/, '"}');

      // Parse the JSON string
      let jsonData;
      try {
        jsonData = JSON.parse(cleanedJsonString);
      } catch (parseError) {
        // If parsing fails, try to fix common JSON issues
        // This is a more aggressive fix for severely truncated JSON
        const fixedJsonString = cleanedJsonString
          .replace(/\{([^}]*)$/, '{$1}')  // Close unclosed object
          .replace(/,\s*$/, '');          // Remove trailing comma

        jsonData = JSON.parse(fixedJsonString);
      }

      // Process the SharePoint data
      const result = processSharePointPageEntity(jsonData);

      // Add the result to the output
      results.push({
        json: result
      });
    } catch (error) {
      results.push({
        json: {
          id: "parsing_error",
          content: `Error parsing JSON: ${error.message}`,
          webUrl: "unknown",
          creatorName: "unknown",
          creatorEmail: "unknown",
          createdDateTime: "unknown",
          lastModifiedDateTime: "unknown",
          formattedOutput: `id:parsing_error\ncontent:Error parsing JSON: ${error.message}`,
          error: error.message
        }
      });
    }
  }

  return results;
}

// Execute the function with the items from n8n
return processItems($input.all());
